import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int A = sc.nextInt();
            int B = sc.nextInt();
            int C = sc.nextInt();
            int P = sc.nextInt();
            int count = 0;
            for (int w = 0; w < P; w++) {
                int l = (A * w + B) % P;
                int cells = (l * w) % P;
                if ((cells + C) % P == 0) {
                    count++;
                }
            }
            System.out.print(count);
            for (int w = 0; w < P; w++) {
                int l = (A * w + B) % P;
                int cells = (l * w) % P;
                if ((cells + C) % P == 0) {
                    System.out.print(" " + w);
                }
            }
            System.out.println();
        }
    }
}

