const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const input = () => lines[idx++].trim();
const T = parseInt(input());
for (let i = 0; i < T; i++) {
    const [A, B, C, P] = input().split(' ').map(Number);
    let count = 0;
    let result = '';
    for (let w = 0; w < P; w++) {
        let l = (A * w + B) % P;
        let cells = (l * w) % P;
        if ((cells + C) % P === 0) {
            count++;
            result += w + ' ';
        }
    }
    console.log(count + ' ' + result);
}
